+const (
+	reloadErrorNone     = "none"
+	reloadErrorLoad     = "load_error"
+	reloadErrorApply    = "apply_error"
+	reloadErrorRollback = "rollback_error"
+)
+
+type transactionalReloadManager struct {
+	path   string
+	logger *slog.Logger
+
+	mu            sync.RWMutex
+	lastKnownGood *config.Config
+	status        web.ReloadStatus
+}
+
+func newTransactionalReloadManager(path string, logger *slog.Logger) *transactionalReloadManager {
+	m := &transactionalReloadManager{
+		path:   path,
+		logger: logger,
+		status: emptyReloadStatus(),
+	}
+	m.load()
+	return m
+}
+
+func emptyReloadStatus() web.ReloadStatus {
+	return web.ReloadStatus{
+		ErrorCategory:     reloadErrorNone,
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]float64{},
+	}
+}
+
+func (m *transactionalReloadManager) load() {
+	b, err := os.ReadFile(m.path)
+	if err != nil {
+		if !os.IsNotExist(err) {
+			m.logger.Warn("Unable to read transactional reload status", "path", m.path, "err", err)
+		}
+		return
+	}
+	var status web.ReloadStatus
+	if err := json.Unmarshal(b, &status); err != nil {
+		m.logger.Warn("Unable to parse transactional reload status", "path", m.path, "err", err)
+		return
+	}
+	if status.ErrorCategory != reloadErrorNone && status.ErrorCategory != reloadErrorLoad && status.ErrorCategory != reloadErrorApply && status.ErrorCategory != reloadErrorRollback {
+		m.logger.Warn("Ignoring transactional reload status with invalid error category", "path", m.path)
+		return
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]float64{}
+	}
+	m.status = status
+}
+
+func (m *transactionalReloadManager) Status() web.ReloadStatus {
+	m.mu.RLock()
+	defer m.mu.RUnlock()
+	status := m.status
+	status.AppliedReloaders = append([]string(nil), status.AppliedReloaders...)
+	status.ReloaderTimingsMS = make(map[string]float64, len(m.status.ReloaderTimingsMS))
+	for name, duration := range m.status.ReloaderTimingsMS {
+		status.ReloaderTimingsMS[name] = duration
+	}
+	return status
+}
+
+func (m *transactionalReloadManager) SetLastKnownGood(filename string, enableExemplarStorage bool) error {
+	conf, err := loadConfig(filename, enableExemplarStorage, m.logger)
+	if err != nil {
+		return err
+	}
+	m.mu.Lock()
+	defer m.mu.Unlock()
+	m.lastKnownGood = conf
+	return nil
+}
+
+func (m *transactionalReloadManager) reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
+	start := time.Now()
+	status := emptyReloadStatus()
+	status.LastReloadID = start.UTC().Format(time.RFC3339Nano)
+	defer func() {
+		status.LastReloadSuccessful = err == nil
+		m.record(status)
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+	}()
+
+	conf, err := loadConfig(filename, enableExemplarStorage, logger)
+	if err != nil {
+		status.ErrorCategory = reloadErrorLoad
+		status.ErrorMessage = err.Error()
+		return err
+	}
+
+	for _, rl := range rls {
+		rstart := time.Now()
+		rlErr := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = float64(time.Since(rstart)) / float64(time.Millisecond)
+		if rlErr != nil {
+			status.ErrorCategory = reloadErrorApply
+			status.ErrorMessage = rlErr.Error()
+			status.FailedReloader = rl.name
+			err = fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, rlErr)
+			break
+		}
+		status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+	}
+	if err != nil {
+		m.rollback(&status, logger, rls...)
+		return err
+	}
+
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	m.mu.Lock()
+	m.lastKnownGood = conf
+	m.mu.Unlock()
+	logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
+	return nil
+}
+
+func (m *transactionalReloadManager) rollback(status *web.ReloadStatus, logger *slog.Logger, rls ...reloader) {
+	if len(status.AppliedReloaders) == 0 {
+		return
+	}
+	m.mu.RLock()
+	knownGood := m.lastKnownGood
+	m.mu.RUnlock()
+	if knownGood == nil {
+		return
+	}
+
+	status.RollbackAttempted = true
+	status.RollbackSuccessful = true
+	for _, rl := range rls {
+		if err := rl.reloader(knownGood); err != nil {
+			logger.Error("Failed to roll back configuration", "reloader", rl.name, "err", err)
+			status.RollbackSuccessful = false
+			status.ErrorCategory = reloadErrorRollback
+			status.ErrorMessage = fmt.Sprintf("%s; rollback with reloader %q failed: %s", status.ErrorMessage, rl.name, err)
+		}
+	}
