+	if err != nil {
+		m.logger.Error("Unable to serialize transactional reload status", "err", err)
+		return
+	}
+	if err := os.MkdirAll(filepath.Dir(m.path), 0o755); err != nil {
+		m.logger.Error("Unable to create transactional reload status directory", "path", m.path, "err", err)
+		return
+	}
+	tmp, err := os.CreateTemp(filepath.Dir(m.path), ".reload-status-*")
+	if err != nil {
+		m.logger.Error("Unable to create transactional reload status file", "path", m.path, "err", err)
+		return
+	}
+	tmpName := tmp.Name()
+	defer os.Remove(tmpName)
+	if _, err := tmp.Write(b); err != nil {
+		tmp.Close()
+		m.logger.Error("Unable to write transactional reload status", "path", m.path, "err", err)
+		return
+	}
+	if err := tmp.Chmod(0o644); err != nil {
+		tmp.Close()
+		m.logger.Error("Unable to set transactional reload status permissions", "path", m.path, "err", err)
+		return
+	}
+	if err := tmp.Close(); err != nil {
+		m.logger.Error("Unable to close transactional reload status", "path", m.path, "err", err)
+		return
+	}
+	if err := os.Rename(tmpName, m.path); err != nil {
+		m.logger.Error("Unable to persist transactional reload status", "path", m.path, "err", err)
+	}
