// initialLoad applies the startup configuration and retains the exact configuration
// that was applied. Startup is not a reload attempt and is deliberately not persisted.
func (m *transactionalReloadManager) initialLoad(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, rls ...reloader) error {
	start := time.Now()
	conf, err := loadConfig(filename, enableExemplarStorage, logger)
	if err != nil {
		configSuccess.Set(0)
		return err
	}

	failed := false
	timingsLogger := logger
	for _, rl := range rls {
		rstart := time.Now()
		if err := rl.reloader(conf); err != nil {
			logger.Error("Failed to apply configuration", "err", err)
			failed = true
		}
		timingsLogger = timingsLogger.With(rl.name, time.Since(rstart))
	}
	if failed {
		configSuccess.Set(0)
		return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", filename)
	}

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	configSuccess.Set(1)
	configSuccessTime.SetToCurrentTime()
	m.mu.Lock()
	m.lastKnownGood = conf
	m.mu.Unlock()
	timingsLogger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
	return nil
}

func (m *transactionalReloadManager) reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
	start := time.Now()
	status := emptyReloadStatus()
	status.LastReloadID = start.UTC().Format(time.RFC3339Nano)
	defer func() {
		status.LastReloadSuccessful = err == nil
		m.record(status)
		if err == nil {
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			callback(true)
		} else {
			configSuccess.Set(0)
			callback(false)
		}
	}()

	conf, err := loadConfig(filename, enableExemplarStorage, logger)
	if err != nil {
		status.ErrorCategory = reloadErrorLoad
		status.ErrorMessage = err.Error()
		return err
	}

	for _, rl := range rls {
		rstart := time.Now()
		rlErr := rl.reloader(conf)
		status.ReloaderTimingsMS[rl.name] = float64(time.Since(rstart)) / float64(time.Millisecond)
		if rlErr != nil {
			status.ErrorCategory = reloadErrorApply
			status.ErrorMessage = rlErr.Error()
			status.FailedReloader = rl.name
			err = fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, rlErr)
			break
		}
		status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
	}
	if err != nil {
		m.rollback(&status, logger, rls...)
		return err
	}

